import { SeriesCurve } from '../../../types/timeseries.js';
import type { PointShapeType } from '../../shape/type.js';
import { CanvasGradientGenerator } from '../utils/create-canvas-gradient.js';

/**
 * @param ctx - canvas context
 * @param id - shapeId
 * @returns -
 */
export type CanvasDraw = (ctx: CanvasRenderingContext2D, id?: string) => void;

export type CanvasShape = {
  id: string;
  /** Handler containing the drawing logic of the shape **/
  draw: CanvasDraw;
};

interface CanvasInstance<Datum> {
  canvasWidth: number;
  canvasHeight: number;
  data: Datum[];
  strokeColor?: (d: Datum) => string;
  displayScatterPlot?: (data: Datum[], index: number) => boolean;
  defined?: (point: Datum) => boolean;
}

interface CanvasColor<Datum> {
  color: (point: Datum) => string;
}

interface BarCanvasColor<Datum> extends CanvasColor<Datum> {
  opacity: (point: Datum) => number;
}

interface LinearCanvasColor<Datum> extends CanvasColor<Datum> {
  opacity?: number;
}

interface CanvasGradientColor<Datum> {
  color: (d: Datum) => string | CanvasGradientGenerator;
  opacity?: number;
}

export interface LineCanvasInstance<Datum>
  extends CanvasInstance<Datum>,
    LinearCanvasColor<Datum> {
  x: (d: Datum) => number;
  y: (d: Datum) => number;
  curve?: SeriesCurve;
}

export interface DotCanvasInstance<Datum>
  extends CanvasInstance<Datum>,
    LinearCanvasColor<Datum> {
  x: (d: Datum) => number;
  y: (d: Datum) => number;
}

export interface BarCanvasInstance<Datum>
  extends CanvasInstance<Datum>,
    BarCanvasColor<Datum> {
  x: (d: Datum, index: number) => number;
  y: (d: Datum, index: number) => number;
  width: (d: Datum) => number;
  height: (d: Datum) => number;
  isVertical?: boolean;
}

export const ORIENTATION_VERTICAL = 'vertical';
export const ORIENTATION_HORIZONTAL = 'horizontal';

export type Orientation =
  | typeof ORIENTATION_VERTICAL
  | typeof ORIENTATION_HORIZONTAL;

export interface AreaCanvasInstance<Datum>
  extends CanvasInstance<Datum>,
    CanvasGradientColor<Datum> {
  x: (point: Datum) => number;
  y0: (point: Datum) => number;
  y1: (point: Datum) => number;
  lineColor?: (point: Datum) => string;
  lineStrokeWidth?: number;
  curve?: SeriesCurve;
  orientation?: Orientation;
  showBandedArea?: boolean;
}

interface CanvasColorProps<Datum> {
  color: (point: Datum) => string;
}

interface BarCanvasColorProps<Datum> extends CanvasColorProps<Datum> {
  opacity: (point: Datum) => number;
}

interface LinearCanvasColorProps<Datum> extends CanvasColorProps<Datum> {
  opacity?: number;
}

interface CanvasShapeProps<Datum> {
  data: Datum[];
  canvasWidth: number;
  canvasHeight: number;
  strokeColor?: (point: Datum) => string;
  strokeWidth?: number;
}

interface ShapeWithScatterProps<Datum> {
  radius?: number;
  displayScatterPlot?: (data: Datum[], index: number) => boolean;
  enableDotOverflow?: boolean;
}

export interface LineCanvasProps<Datum>
  extends CanvasShapeProps<Datum>,
    LinearCanvasColorProps<Datum>,
    ShapeWithScatterProps<Datum> {
  x: (point: Datum) => number;
  y: (point: Datum) => number;
  defined?: (point: Datum) => boolean;
  curve?: SeriesCurve;
  overlayPadding?: number;
}

export interface AreaCanvasProps<Datum>
  extends CanvasShapeProps<Datum>,
    CanvasGradientColor<Datum>,
    ShapeWithScatterProps<Datum> {
  x: (point: Datum) => number;
  y0: (point: Datum) => number;
  y1: (point: Datum) => number;
  defined?: (point: Datum) => boolean;
  lineColor?: (point: Datum) => string;
  lineStrokeWidth?: number;
  curve?: SeriesCurve;
  enableDotOverflow?: boolean;
  overlayPadding?: number;
  orientation?: Orientation;
  showBandedArea?: boolean;
}

export interface BarCanvasProps<Datum>
  extends CanvasShapeProps<Datum>,
    BarCanvasColorProps<Datum> {
  x: (point: Datum, index: number) => number;
  y: (point: Datum, index: number) => number;
  width: (point: Datum) => number;
  height: (point: Datum) => number;
  isVertical?: boolean;
  defined?: (point: Datum) => boolean;
  enableDotOverflow?: boolean;
  overlayPadding?: number;
}

export interface DotCanvasProps<Datum>
  extends CanvasShapeProps<Datum>,
    LinearCanvasColorProps<Datum> {
  //create new type that contains stroke width and color and extend it instead?
  radius?: number;
  x: (point: Datum) => number;
  y: (point: Datum) => number;
  defined?: (point: Datum) => boolean;
  shape?: PointShapeType;
  enableDotOverflow?: boolean;
}

export type FnCanvasAccessor<Datum> = (d: Datum, i: number) => number;

/**
 * Whether to show data points always, never, or depending on a width-based threshold amount
 * @public
 */
export const pointsDisplayOptions = ['always', 'never', 'auto'] as const;
/**
 * @public
 */
export type PointsDisplay = (typeof pointsDisplayOptions)[number];
